#include <stdio.h>
#include <stdlib.h>

int countPainters(int* boards, int boardsSize, int time) {
    int painters = 1;
    int boardsPainter = 0;
    for (int i = 0; i < boardsSize; i++) {
        if (boardsPainter + boards[i] <= time) {
            boardsPainter += boards[i];
        } else {
            painters++;
            boardsPainter = boards[i];
        }
    }
    return painters;
}

int findLargestMinDistance(int* boards, int boardsSize, int k) {
    int low = boards[0];
    int high = 0;
    for (int i = 0; i < boardsSize; i++) {
        if (boards[i] > low) low = boards[i];
        high += boards[i];
    }
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (countPainters(boards, boardsSize, mid) <= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

int main() {
    int boards[] = {10, 20, 30, 40, 50};
    int k = 3;
    int boardsSize = sizeof(boards) / sizeof(boards[0]);
    int ans = findLargestMinDistance(boards, boardsSize, k);
    printf("The answer is: %d\n", ans);
    return 0;
}

