class PainterPartition {
    // Count how many painters are required if each painter can paint at most 'time' units
    countPainters(boards, time) {
        let painters = 1;         // Start with one painter
        let boardsPainter = 0;    // Current painter's load

        for (let board of boards) {
            if (boardsPainter + board <= time) {
                // Assign board to current painter
                boardsPainter += board;
            } else {
                // Assign board to next painter
                painters++;
                boardsPainter = board;
            }
        }

        return painters;
    }

    // Find the minimum time needed to paint all boards using k painters
    findLargestMinDistance(boards, k) {
        const low = Math.max(...boards);             // No painter can handle less than max board
        const high = boards.reduce((a, b) => a + b); // Sum of all boards (worst case)

        let left = low;
        let right = high;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (this.countPainters(boards, mid) <= k) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;  // Fallback
    }
}

